  calVideoLogo           String?
  appLogo                String?
  appIconLogo            String?
  bio                    String?
  hideBranding           Boolean                 @default(false)
  isPrivate              Boolean                 @default(false)
  hideBookATeamMember    Boolean                 @default(false)
  members                Membership[]
  eventTypes             EventType[]
  workflows              Workflow[]
  createdAt              DateTime                @default(now())
  /// @zod.custom(imports.teamMetadataSchema)
  metadata               Json?
