  // User's email at the time of booking
  /// @zod.email()
  userPrimaryEmail      String?
  references            BookingReference[]
  eventType             EventType?                 @relation(fields: [eventTypeId], references: [id])
  eventTypeId           Int?
  title                 String
  description           String?
  customInputs          Json?
  /// @zod.custom(imports.bookingResponses)
  responses             Json?
